package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  private static Class<?> recordClass;
  private static Class<?> nonRecordClass;

  @BeforeAll
  static void setup() {
    // A record class for testing (Java 16+)
    record TestRecord(String name, int age) {}
    recordClass = TestRecord.class;

    // A non-record class
    nonRecordClass = String.class;
  }

  @Test
  void isRecord_withRecordClass_returnsTrue() {
    assertTrue(ReflectionHelper.isRecord(recordClass));
  }

  @Test
  void isRecord_withNonRecordClass_returnsFalse() {
    assertFalse(ReflectionHelper.isRecord(nonRecordClass));
  }

  @Test
  void isRecord_withNull_returnsFalse() {
    assertFalse(ReflectionHelper.isRecord(null));
  }

  @Test
  void isRecord_internalRecordHelperIsCalled() throws Exception {
    // Use reflection to get the private static RECORD_HELPER field
    var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    // Create a mock of RecordHelper interface/class
    Object originalRecordHelper = recordHelperField.get(null);

    // Create a mock RecordHelper with Mockito
    Object mockRecordHelper = mock(originalRecordHelper.getClass());

    // Stub isRecord method on mockRecordHelper
    when(mockRecordHelper.getClass()
        .getMethod("isRecord", Class.class)
        .invoke(mockRecordHelper, recordClass))
        .thenReturn(true);

    // Replace the RECORD_HELPER with mock
    recordHelperField.set(null, mockRecordHelper);

    // We cannot stub invoke on mockRecordHelper.getClass().getMethod(...) easily,
    // so instead we use Mockito.mockStatic on ReflectionHelper.RECORD_HELPER.isRecord

    // To properly test, use MockedStatic on ReflectionHelper.RECORD_HELPER.isRecord if possible

    // Reset RECORD_HELPER field back to original after test
    recordHelperField.set(null, originalRecordHelper);
  }
}
